mapper.select:
SELECT
FROM TB_WORD_DICARY_INFO A WHERE 1=1
ORDER BY A.WORD_ID DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

SELECT

  FROM  TB_WORD_DICARY_INFO A
 WHERE  A.WORD_ID = #{wordId}

mapper.insert:
INSERT  INTO TB_WORD_DICARY_INFO
      ( WORD_ID
      , WORD_NM
      , ENG_NM
      , WORD_DC
      , SYNONM
      , FRST_REGIST_PNTTM
      , FRST_REGISTER_ID )
VALUES  ( #{wordId}
        , #{wordNm}
        , #{engNm}
        , #{wordDc}
        , #{synonm}
        , CURRENT_TIMESTAMP
        , #{frstRegisterId} )

mapper.update:
UPDATE  TB_WORD_DICARY_INFO
   SET  WORD_NM = #{wordNm}
      , ENG_NM = #{engNm}
      , WORD_DC = #{wordDc}
      , SYNONM = #{synonm}
      , LAST_UPDUSR_ID = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  WORD_ID = #{wordId}
